---
/**
 * Separator.astro -- astro-shad separator. Converted from shadcn
 * ui/separator.tsx (base-ui Separator primitive): a horizontal or
 * vertical rule, zero client JS -- Radix/base-ui here was only ever
 * doing role="separator" + orientation, both native attributes.
 *
 * decorative (default true) sets role="none" so screen readers skip a
 * purely visual rule; pass decorative={false} for a rule that carries
 * real document structure.
 *
 *   <Separator />
 *   <Separator orientation="vertical" class="h-6" />
 */
import { cn } from '../../lib/utils';

interface Props {
  orientation?: 'horizontal' | 'vertical';
  decorative?: boolean;
  class?: string;
  [key: string]: unknown;
}

const {
  orientation = 'horizontal',
  decorative = true,
  class: className,
  ...rest
} = Astro.props;
---

<div
  data-slot="separator"
  role={decorative ? 'none' : 'separator'}
  aria-orientation={decorative ? undefined : orientation}
  class={cn(
    'shrink-0 bg-border',
    orientation === 'horizontal' ? 'h-px w-full' : 'h-full w-px self-stretch',
    className
  )}
  {...rest}
/>
